import os
import shutil
from datetime import datetime
import tarfile
import zipfile
import rarfile
import py7zr

def backup_directory(directory, format):
    if not os.path.exists(directory):
        print(f"Error: Directory '{directory}' does not exist.")
        return
    
    timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
    
    if format == "tar.gz":
        filename = f"{timestamp}.tar.gz"
        with tarfile.open(filename, "w:gz") as tar:
            tar.add(directory)
    elif format == "tar.bz2":
        filename = f"{timestamp}.tar.bz2"
        with tarfile.open(filename, "w:bz2") as tar:
            tar.add(directory)
    elif format == "zip":
        filename = f"{timestamp}.zip"
        with zipfile.ZipFile(filename, "w") as zip_file:
            for root, dirs, files in os.walk(directory):
                for file in files:
                    filepath = os.path.join(root, file)
                    relpath = os.path.relpath(filepath, directory)
                    zip_file.write(filepath, relpath)
    elif format == "7z":
        filename = f"{timestamp}.7z"
        with py7zr.SevenZipFile(filename, mode="w") as sevenzip:
            for root, dirs, files in os.walk(directory):
                for file in files:
                    filepath = os.path.join(root, file)
                    relpath = os.path.relpath(filepath, directory)
                    sevenzip.write(filepath, relpath)
    else:
        print(f"Error: Unsupported format '{format}'.")
        return
    
    print(f"Backup created at {os.getcwd()}/{filename}")

if __name__ == "__main__":
    import argparse
    parser = argparse.ArgumentParser(description="Create a compressed backup of a directory.")
    parser.add_argument("directory", help="Path to the directory to be backed up.")
    parser.add_argument("-f", "--format", default="zip", choices=["tar.gz", "tar.bz2", "zip", "7z"], help="Compression format (default: zip)")
    args = parser.parse_args()
    
    backup_directory(args.directory, args.format)